shape.script:
function getHandles(params) {
    let radius = params.radius;
    let sideCount = params.sideCount;
    let radsPerSide = 2.0*Math.PI/sideCount;
    let offsetAngle = params.offsetAngle * Math.PI / 180.0;

    let handleAngle = Math.PI/2.0 + offsetAngle - radsPerSide * Math.floor(sideCount/3);

    return {
        r: [radius*Math.cos(handleAngle),radius*-Math.sin(handleAngle)],
        a: [radius*Math.cos(offsetAngle + Math.PI/2.0),radius*-Math.sin(offsetAngle + Math.PI/2.0)],
    }
}

function getPath(params) {
    let radius = params.radius;
    let sideCount = params.sideCount;
    let offsetAngle = params.offsetAngle * Math.PI / 180.0;
    let points = [];
    let radsPerSide = 2.0*Math.PI/sideCount;
    for( let i=0; i<sideCount; i++ ) {
        let angle = radsPerSide*i + Math.PI/2.0 + offsetAngle;
        points.push([radius*Math.cos(angle),radius*-Math.sin(angle)]);

    }
    points.push({closed:true});
    return points;
}
